import Foundation
import Testing
@testable import AIUsagesTrackersLib

// MARK: - URL mocking

final class MockURLProtocol: URLProtocol, @unchecked Sendable {
    nonisolated(unsafe) static var handler: ((URLRequest) -> (Data, HTTPURLResponse))?

    override class func canInit(with request: URLRequest) -> Bool { true }
    override class func canonicalRequest(for request: URLRequest) -> URLRequest { request }

    override func startLoading() {
        guard let handler = Self.handler else {
            client?.urlProtocolDidFinishLoading(self)
            return
        }
        let (data, response) = handler(request)
        client?.urlProtocol(self, didReceive: response, cacheStoragePolicy: .notAllowed)
        client?.urlProtocol(self, didLoad: data)
        client?.urlProtocolDidFinishLoading(self)
    }

    override func stopLoading() {}
}

private func mockSession() -> URLSession {
    let config = URLSessionConfiguration.ephemeral
    config.protocolClasses = [MockURLProtocol.self]
    return URLSession(configuration: config)
}

// MARK: - Account resolution tests

@Suite("ClaudeCodeConnector — account resolution")
struct ClaudeCodeConnectorAccountTests {
    private func makeTempDir() -> String {
        let dir = NSTemporaryDirectory() + "ai-tracker-claude-\(UUID().uuidString)"
        try! FileManager.default.createDirectory(atPath: dir, withIntermediateDirectories: true)
        return dir
    }

    @Test("resolves email from valid claude.json")
    func resolveValid() {
        let dir = makeTempDir()
        let configPath = "\(dir)/claude.json"
        let json = #"{"oauthAccount":{"emailAddress":"user@example.com","accountUuid":"abc"}}"#
        try! json.write(toFile: configPath, atomically: true, encoding: .utf8)

        let logger = FileLogger(filePath: "\(dir)/test.log", minLevel: .debug)
        let connector = ClaudeCodeConnector(claudeConfigPath: configPath, logger: logger)
        #expect(connector.resolveActiveAccount() == "user@example.com")
    }

    @Test("returns nil when file is missing")
    func resolveMissing() {
        let logger = FileLogger(filePath: "/tmp/ai-tracker-test-\(UUID()).log", minLevel: .debug)
        let connector = ClaudeCodeConnector(claudeConfigPath: "/nonexistent/path", logger: logger)
        #expect(connector.resolveActiveAccount() == nil)
    }

    @Test("returns nil when JSON lacks oauthAccount")
    func resolveNoOauth() {
        let dir = makeTempDir()
        let configPath = "\(dir)/claude.json"
        try! "{}".write(toFile: configPath, atomically: true, encoding: .utf8)

        let logger = FileLogger(filePath: "\(dir)/test.log", minLevel: .debug)
        let connector = ClaudeCodeConnector(claudeConfigPath: configPath, logger: logger)
        #expect(connector.resolveActiveAccount() == nil)
    }

    @Test("returns nil when JSON is malformed")
    func resolveMalformed() {
        let dir = makeTempDir()
        let configPath = "\(dir)/claude.json"
        try! "not json".write(toFile: configPath, atomically: true, encoding: .utf8)

        let logger = FileLogger(filePath: "\(dir)/test.log", minLevel: .debug)
        let connector = ClaudeCodeConnector(claudeConfigPath: configPath, logger: logger)
        #expect(connector.resolveActiveAccount() == nil)
    }
}

// MARK: - fetchUsages tests

@Suite("ClaudeCodeConnector — fetchUsages", .serialized)
struct ClaudeCodeConnectorFetchTests {
    private func makeTempDir() -> String {
        let dir = NSTemporaryDirectory() + "ai-tracker-claude-fetch-\(UUID().uuidString)"
        try! FileManager.default.createDirectory(atPath: dir, withIntermediateDirectories: true)
        return dir
    }

    private func makeConnector(dir: String, tokenProvider: @escaping @Sendable () async throws -> String) -> ClaudeCodeConnector {
        let configPath = "\(dir)/claude.json"
        let json = #"{"oauthAccount":{"emailAddress":"user@example.com"}}"#
        try! json.write(toFile: configPath, atomically: true, encoding: .utf8)
        let logger = FileLogger(filePath: "\(dir)/test.log", minLevel: .debug)
        return ClaudeCodeConnector(
            claudeConfigPath: configPath,
            logger: logger,
            session: mockSession(),
            tokenProvider: tokenProvider
        )
    }

    @Test("success path returns entry with two metrics")
    func successPath() async throws {
        let dir = makeTempDir()
        let apiJSON = """
        {"five_hour":{"utilization":42,"resets_at":"2026-04-17T15:00:00+00:00"},
         "seven_day":{"utilization":8,"resets_at":"2026-04-23T21:00:00+00:00"}}
        """
        MockURLProtocol.handler = { _ in
            let data = apiJSON.data(using: .utf8)!
            let resp = HTTPURLResponse(url: URL(string: "https://api.anthropic.com")!, statusCode: 200, httpVersion: nil, headerFields: nil)!
            return (data, resp)
        }
        let connector = makeConnector(dir: dir) { "fake-token" }
        let entries = try await connector.fetchUsages()

        #expect(entries.count == 1)
        #expect(entries[0].account == "user@example.com")
        #expect(entries[0].lastError == nil)
        #expect(entries[0].metrics.count == 2)
        // utilization is a Double from the API; connector rounds to nearest Int percent (42.0 → 42)
        if case .timeWindow(let name, _, _, let pct) = entries[0].metrics[0] {
            #expect(name == "session")
            #expect(pct == 42)
        } else {
            Issue.record("Expected timeWindow metric for session")
        }
        if case .timeWindow(let name, _, let duration, let pct) = entries[0].metrics[1] {
            #expect(name == "weekly")
            #expect(pct == 8)
            #expect(duration == 10080)
        } else {
            Issue.record("Expected timeWindow metric for weekly")
        }
    }

    @Test("token error returns error entry")
    func tokenError() async throws {
        let dir = makeTempDir()
        let connector = makeConnector(dir: dir) { throw ConnectorError.keychainAccessDenied(serviceName: "test", exitCode: 1) }
        let entries = try await connector.fetchUsages()

        #expect(entries.count == 1)
        #expect(entries[0].lastError?.type == "token_error")
        #expect(entries[0].metrics.isEmpty)
    }

    @Test("HTTP 401 returns error entry")
    func httpError() async throws {
        let dir = makeTempDir()
        MockURLProtocol.handler = { _ in
            let resp = HTTPURLResponse(url: URL(string: "https://api.anthropic.com")!, statusCode: 401, httpVersion: nil, headerFields: nil)!
            return (Data(), resp)
        }
        let connector = makeConnector(dir: dir) { "fake-token" }
        let entries = try await connector.fetchUsages()

        #expect(entries.count == 1)
        #expect(entries[0].lastError?.type == "http_401")
    }

    @Test("HTTP 429 preserves previous metrics and sets rate-limit error")
    func rateLimited() async throws {
        let dir = makeTempDir()
        let connector = makeConnector(dir: dir) { "fake-token" }

        // First call succeeds — seeds lastKnownMetrics
        MockURLProtocol.handler = { _ in
            let data = """
            {"five_hour":{"utilization":0.5,"resets_at":"2025-01-01T00:00:00Z"},
             "seven_day":{"utilization":0.3,"resets_at":"2025-01-07T00:00:00Z"}}
            """.data(using: .utf8)!
            let resp = HTTPURLResponse(url: URL(string: "https://api.anthropic.com")!, statusCode: 200, httpVersion: nil, headerFields: nil)!
            return (data, resp)
        }
        let firstEntries = try await connector.fetchUsages()
        #expect(firstEntries[0].metrics.count == 2)

        // Second call returns 429 — metrics must be preserved
        MockURLProtocol.handler = { _ in
            let body = #"{"error":"rate limited"}"#.data(using: .utf8)!
            let resp = HTTPURLResponse(url: URL(string: "https://api.anthropic.com")!, statusCode: 429, httpVersion: nil, headerFields: nil)!
            return (body, resp)
        }
        let rateLimitedEntries = try await connector.fetchUsages()

        #expect(rateLimitedEntries.count == 1)
        #expect(rateLimitedEntries[0].lastError?.type == "http_429")
        #expect(rateLimitedEntries[0].metrics.count == 2)
        #expect(rateLimitedEntries[0].metrics == firstEntries[0].metrics)
    }

    @Test("malformed API response returns parse error entry")
    func parseError() async throws {
        let dir = makeTempDir()
        MockURLProtocol.handler = { _ in
            let data = "{}".data(using: .utf8)!
            let resp = HTTPURLResponse(url: URL(string: "https://api.anthropic.com")!, statusCode: 200, httpVersion: nil, headerFields: nil)!
            return (data, resp)
        }
        let connector = makeConnector(dir: dir) { "fake-token" }
        let entries = try await connector.fetchUsages()

        #expect(entries.count == 1)
        #expect(entries[0].lastError?.type == "parse_error")
    }

    @Test("resets_at with fractional seconds is normalized to whole-second ISO8601")
    func resetsAtFractionalSecondsNormalized() async throws {
        let dir = makeTempDir()
        let apiJSON = """
        {"five_hour":{"utilization":5,"resets_at":"2026-04-23T19:00:00.107277+00:00"},
         "seven_day":{"utilization":17,"resets_at":"2026-04-24T00:00:00.999999+00:00"}}
        """
        MockURLProtocol.handler = { _ in
            let data = apiJSON.data(using: .utf8)!
            let resp = HTTPURLResponse(url: URL(string: "https://api.anthropic.com")!, statusCode: 200, httpVersion: nil, headerFields: nil)!
            return (data, resp)
        }
        let connector = makeConnector(dir: dir) { "fake-token" }
        let entries = try await connector.fetchUsages()

        #expect(entries.count == 1)
        if case .timeWindow(_, let sessionResetAt, _, _) = entries[0].metrics[0] {
            // Fractional seconds must be stripped; standard ISO8601DateFormatter must parse the result
            #expect(sessionResetAt.date != nil)
            #expect(!sessionResetAt.rawValue.contains("."))
        } else {
            Issue.record("Expected timeWindow metric for session")
        }
        if case .timeWindow(_, let weeklyResetAt, _, _) = entries[0].metrics[1] {
            #expect(weeklyResetAt.date != nil)
            #expect(!weeklyResetAt.rawValue.contains("."))
        } else {
            Issue.record("Expected timeWindow metric for weekly")
        }
    }

    @Test("nil account returns account_unknown error entry")
    func unknownAccount() async throws {
        let dir = makeTempDir()
        let logger = FileLogger(filePath: "\(dir)/test.log", minLevel: .debug)
        // No claude.json → resolveActiveAccount returns nil
        let connector = ClaudeCodeConnector(
            claudeConfigPath: "\(dir)/missing.json",
            logger: logger,
            session: mockSession(),
            tokenProvider: { "fake-token" }
        )
        let entries = try await connector.fetchUsages()

        #expect(entries.count == 1)
        #expect(entries[0].lastError?.type == "account_unknown")
    }
}

import Foundation
import Testing
@testable import AIUsagesTrackersLib

// MARK: - Mock connector

actor MockConnector: UsageConnector {
    nonisolated let vendor: Vendor
    private let entries: [VendorUsageEntry]
    private let shouldThrow: Bool
    private(set) var fetchCount = 0

    init(vendor: Vendor, entries: [VendorUsageEntry], shouldThrow: Bool = false) {
        self.vendor = vendor
        self.entries = entries
        self.shouldThrow = shouldThrow
    }

    nonisolated func resolveActiveAccount() -> AccountEmail? {
        entries.first?.account
    }

    func fetchUsages() async throws -> [VendorUsageEntry] {
        fetchCount += 1
        if shouldThrow { throw ConnectorError.unexpectedAPIFormat(receivedKeys: []) }
        return entries
    }
}

// MARK: - Tests

@Suite("UsagePoller")
struct UsagePollerTests {
    private func makeTempDir() -> String {
        let dir = NSTemporaryDirectory() + "ai-tracker-poller-\(UUID().uuidString)"
        try! FileManager.default.createDirectory(atPath: dir, withIntermediateDirectories: true)
        return dir
    }

    @Test("pollOnce writes entries to file")
    func pollOnceWrites() async {
        let dir = makeTempDir()
        let logger = FileLogger(filePath: "\(dir)/test.log", minLevel: .debug)
        let fm = UsagesFileManager(filePath: "\(dir)/usages.json", logger: logger)
        let entry = VendorUsageEntry(vendor: "claude", account: "a@b.com", isActive: true, metrics: [
            .timeWindow(name: "session", resetAt: "2026-04-17T15:00:00+00:00",
                        windowDuration: 300, usagePercent: 42),
        ])
        let connector = MockConnector(vendor: "claude", entries: [entry])
        let poller = UsagePoller(connectors: [connector], fileManager: fm, logger: logger)

        await poller.pollOnce()

        let result = await fm.read()
        #expect(result.usages.count == 1)
        #expect(result.usages[0].account == "a@b.com")
    }

    @Test("pollOnce with throwing connector still writes other connectors' results")
    func pollOncePartialFailure() async {
        let dir = makeTempDir()
        let logger = FileLogger(filePath: "\(dir)/test.log", minLevel: .debug)
        let fm = UsagesFileManager(filePath: "\(dir)/usages.json", logger: logger)

        let good = MockConnector(vendor: "claude", entries: [
            VendorUsageEntry(vendor: "claude", account: "a@b.com", isActive: true),
        ])
        let bad = MockConnector(vendor: "codex", entries: [], shouldThrow: true)
        let poller = UsagePoller(connectors: [good, bad], fileManager: fm, logger: logger)

        await poller.pollOnce()

        let result = await fm.read()
        #expect(result.usages.count == 1)
        #expect(result.usages[0].vendor == "claude")
    }

    @Test("pollOnce with all connectors failing writes nothing")
    func pollOnceAllFail() async {
        let dir = makeTempDir()
        let logger = FileLogger(filePath: "\(dir)/test.log", minLevel: .debug)
        let fm = UsagesFileManager(filePath: "\(dir)/usages.json", logger: logger)

        let bad = MockConnector(vendor: "claude", entries: [], shouldThrow: true)
        let poller = UsagePoller(connectors: [bad], fileManager: fm, logger: logger)

        await poller.pollOnce()

        let result = await fm.read()
        #expect(result.usages.isEmpty)
    }

    @Test("pollOnce aggregates multiple connectors")
    func pollOnceMultipleConnectors() async {
        let dir = makeTempDir()
        let logger = FileLogger(filePath: "\(dir)/test.log", minLevel: .debug)
        let fm = UsagesFileManager(filePath: "\(dir)/usages.json", logger: logger)

        let c1 = MockConnector(vendor: "claude", entries: [
            VendorUsageEntry(vendor: "claude", account: "a@b.com", isActive: true),
        ])
        let c2 = MockConnector(vendor: "codex", entries: [
            VendorUsageEntry(vendor: "codex", account: "c@d.com", isActive: true),
        ])
        let poller = UsagePoller(connectors: [c1, c2], fileManager: fm, logger: logger)

        await poller.pollOnce()

        let result = await fm.read()
        #expect(result.usages.count == 2)
    }

    @Test("start is idempotent — calling twice does not double-poll")
    func startIdempotent() async {
        let dir = makeTempDir()
        let logger = FileLogger(filePath: "\(dir)/test.log", minLevel: .debug)
        let fm = UsagesFileManager(filePath: "\(dir)/usages.json", logger: logger)
        let connector = MockConnector(vendor: "claude", entries: [
            VendorUsageEntry(vendor: "claude", account: "a@b.com"),
        ])
        let poller = UsagePoller(
            connectors: [connector],
            interval: .milliseconds(50),
            fileManager: fm,
            logger: logger
        )

        await poller.start()
        await poller.start() // second call should be no-op
        try? await Task.sleep(for: .milliseconds(200))
        await poller.stop()

        // If start were not idempotent, fetchCount would roughly double
        let count = await connector.fetchCount
        #expect(count >= 2 && count <= 6)
    }

    @Test("pollOnce skips fetch when cached data is within interval")
    func pollOnceFreshSkipped() async {
        let dir = makeTempDir()
        let logger = FileLogger(filePath: "\(dir)/test.log", minLevel: .debug)
        let fm = UsagesFileManager(filePath: "\(dir)/usages.json", logger: logger)

        let now = Date()
        let recentDate = now.addingTimeInterval(-60) // 60s ago, well within 180s interval
        let cachedEntry = VendorUsageEntry(
            vendor: "claude", account: "a@b.com", isActive: true,
            lastAcquiredOn: ISODate(date: recentDate),
            metrics: []
        )
        await fm.update(with: [cachedEntry])

        let connector = MockConnector(vendor: "claude", entries: [cachedEntry])
        let poller = UsagePoller(connectors: [connector], interval: .seconds(180), fileManager: fm, logger: logger)

        await poller.pollOnce(now: now)

        let fetchCount = await connector.fetchCount
        #expect(fetchCount == 0)
    }

    @Test("pollOnce fetches when cached data exceeds interval")
    func pollOnceStaleDataFetched() async {
        let dir = makeTempDir()
        let logger = FileLogger(filePath: "\(dir)/test.log", minLevel: .debug)
        let fm = UsagesFileManager(filePath: "\(dir)/usages.json", logger: logger)

        let now = Date()
        let staleDate = now.addingTimeInterval(-200) // 200s ago, past 180s interval
        let staleEntry = VendorUsageEntry(
            vendor: "claude", account: "a@b.com", isActive: true,
            lastAcquiredOn: ISODate(date: staleDate),
            metrics: []
        )
        await fm.update(with: [staleEntry])

        let freshEntry = VendorUsageEntry(
            vendor: "claude", account: "a@b.com", isActive: true,
            lastAcquiredOn: ISODate(date: now),
            metrics: []
        )
        let connector = MockConnector(vendor: "claude", entries: [freshEntry])
        let poller = UsagePoller(connectors: [connector], interval: .seconds(180), fileManager: fm, logger: logger)

        await poller.pollOnce(now: now)

        let fetchCount = await connector.fetchCount
        #expect(fetchCount == 1)
    }

    @Test("pollOnce fetches when no prior entry exists (lastAcquiredOn nil)")
    func pollOnceNoPriorEntry() async {
        let dir = makeTempDir()
        let logger = FileLogger(filePath: "\(dir)/test.log", minLevel: .debug)
        let fm = UsagesFileManager(filePath: "\(dir)/usages.json", logger: logger)

        let entry = VendorUsageEntry(vendor: "claude", account: "a@b.com", isActive: true)
        let connector = MockConnector(vendor: "claude", entries: [entry])
        let poller = UsagePoller(connectors: [connector], interval: .seconds(180), fileManager: fm, logger: logger)

        await poller.pollOnce(now: Date())

        let fetchCount = await connector.fetchCount
        #expect(fetchCount == 1)
    }

    @Test("start/stop lifecycle")
    func startStop() async {
        let dir = makeTempDir()
        let logger = FileLogger(filePath: "\(dir)/test.log", minLevel: .debug)
        let fm = UsagesFileManager(filePath: "\(dir)/usages.json", logger: logger)
        let connector = MockConnector(vendor: "claude", entries: [
            VendorUsageEntry(vendor: "claude", account: "a@b.com"),
        ])
        let poller = UsagePoller(
            connectors: [connector],
            interval: .milliseconds(50),
            fileManager: fm,
            logger: logger
        )

        await poller.start()
        try? await Task.sleep(for: .milliseconds(200))
        await poller.stop()

        let count = await connector.fetchCount
        #expect(count >= 2)
    }
}

import Foundation

public actor ClaudeCodeConnector: UsageConnector {
    nonisolated public let vendor: Vendor = .claude

    private let claudeConfigPath: String
    private let logger: FileLogger
    private let session: URLSession
    private let keychainServiceName: String
    private let tokenProvider: (@Sendable () async throws -> String)?
    private let accountProvider: (@Sendable () -> AccountEmail?)?

    private var lastKnownMetrics: [UsageMetric] = []

    nonisolated(unsafe) private static let isoFormatter = ISO8601DateFormatter()
    // API responses may include sub-second precision; this formatter handles them for normalization
    nonisolated(unsafe) private static let isoFormatterFractional: ISO8601DateFormatter = {
        let f = ISO8601DateFormatter()
        f.formatOptions = [.withInternetDateTime, .withFractionalSeconds]
        return f
    }()

    public init(
        claudeConfigPath: String? = nil,
        logger: FileLogger = Loggers.claude,
        session: URLSession = .shared,
        keychainServiceName: String = "Claude Code-credentials",
        tokenProvider: (@Sendable () async throws -> String)? = nil,
        accountProvider: (@Sendable () -> AccountEmail?)? = nil
    ) {
        let home = FileManager.default.homeDirectoryForCurrentUser.path
        self.claudeConfigPath = claudeConfigPath ?? "\(home)/.claude.json"
        self.logger = logger
        self.session = session
        self.keychainServiceName = keychainServiceName
        self.tokenProvider = tokenProvider
        self.accountProvider = accountProvider
    }

    // MARK: - UsageConnector

    nonisolated public func resolveActiveAccount() -> AccountEmail? {
        if let provider = accountProvider {
            return provider()
        }
        guard let data = FileManager.default.contents(atPath: claudeConfigPath) else {
            logger.log(.warning, "Cannot read \(claudeConfigPath)")
            return nil
        }
        do {
            let json = try JSONSerialization.jsonObject(with: data) as? [String: Any]
            let oauth = json?["oauthAccount"] as? [String: Any]
            return (oauth?["emailAddress"] as? String).map(AccountEmail.init(rawValue:))
        } catch {
            logger.log(.error, "Failed to parse \(claudeConfigPath): \(error)")
            return nil
        }
    }

    public func fetchUsages() async throws -> [VendorUsageEntry] {
        guard let earlyAccount = resolveActiveAccount() else {
            logger.log(.warning, "Cannot resolve active account — skipping fetch")
            return [errorEntry(account: "unknown", type: "account_unknown")]
        }
        logger.log(.info, "Fetching usages for account=\(earlyAccount)")

        let token: String
        do {
            if let provider = tokenProvider {
                token = try await provider()
            } else {
                token = try await fetchOAuthToken()
            }
        } catch {
            logger.log(.error, "Token retrieval failed: \(error)")
            return [errorEntry(account: earlyAccount, type: "token_error")]
        }

        // Re-read at HTTP dispatch time: if the user switched accounts while the token was being
        // fetched, the response must be attributed to whoever was active when the request went out.
        let account = resolveActiveAccount() ?? earlyAccount

        guard let url = URL(string: "https://api.anthropic.com/api/oauth/usage") else {
            return [errorEntry(account: account, type: "api_error")]
        }
        var request = URLRequest(url: url)
        request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        // Required by the OAuth usage endpoint — beta flag must match the rollout date
        request.setValue("oauth-2025-04-20", forHTTPHeaderField: "anthropic-beta")
        request.timeoutInterval = 5

        let data: Data
        let response: URLResponse
        do {
            (data, response) = try await session.data(for: request)
        } catch {
            logger.log(.error, "API request failed: \(error)")
            return [errorEntry(account: account, type: "api_error")]
        }

        let httpCode = (response as? HTTPURLResponse)?.statusCode ?? -1
        logger.log(.info, "API response: HTTP \(httpCode)")

        if httpCode == 429 {
            let body = String(data: data, encoding: .utf8) ?? "<non-UTF8 body, \(data.count) bytes>"
            logger.log(.warning, "API rate-limited (HTTP 429): \(body)")
            return [errorEntry(account: account, type: "http_429", isActive: true, preservedMetrics: lastKnownMetrics)]
        }

        guard let http = response as? HTTPURLResponse, http.statusCode == 200 else {
            logger.log(.error, "API returned HTTP \(httpCode)")
            return [errorEntry(account: account, type: "http_\(httpCode)")]
        }

        logger.log(.debug, "API payload: \(Self.maskedPayload(data))")

        do {
            let usage = try parseAPIResponse(data)
            logger.log(.info, "Fetched successfully: session=\(usage.sessionPercent)% weekly=\(usage.weeklyPercent)%")
            // Window durations are not in the API response — they're fixed by Claude's rate-limit policy
            let metrics: [UsageMetric] = [
                .timeWindow(
                    name: "session",
                    resetAt: usage.sessionResetAt,
                    windowDuration: DurationMinutes(rawValue: 300),  // 5 hours
                    usagePercent: UsagePercent(rawValue: usage.sessionPercent)
                ),
                .timeWindow(
                    name: "weekly",
                    resetAt: usage.weeklyResetAt,
                    windowDuration: DurationMinutes(rawValue: 10080),  // 7 days
                    usagePercent: UsagePercent(rawValue: usage.weeklyPercent)
                ),
            ]
            lastKnownMetrics = metrics
            return [VendorUsageEntry(
                vendor: vendor,
                account: account,
                isActive: true,
                lastAcquiredOn: ISODate(date: Date()),
                lastError: nil,
                metrics: metrics
            )]
        } catch {
            logger.log(.error, "Response parse failed: \(error)")
            return [errorEntry(account: account, type: "parse_error")]
        }
    }

    // MARK: - Token

    private func fetchOAuthToken() async throws -> String {
        let serviceName = keychainServiceName
        return try await withCheckedThrowingContinuation { continuation in
            DispatchQueue.global().async {
                let process = Process()
                let pipe = Pipe()
                process.executableURL = URL(fileURLWithPath: "/usr/bin/security")
                process.arguments = ["find-generic-password", "-s", serviceName, "-w"]
                process.standardOutput = pipe
                process.standardError = FileHandle.nullDevice

                do {
                    try process.run()
                } catch {
                    continuation.resume(throwing: error)
                    return
                }

                // Keychain may prompt the user or hang if the login keychain is locked;
                // 10 s is long enough for a cached lookup, short enough to not stall the poller
                let timedOut = DispatchSemaphore(value: 0)
                DispatchQueue.global().asyncAfter(deadline: .now() + .seconds(10)) {
                    guard process.isRunning else { return }
                    process.terminate()
                    timedOut.signal()
                }

                let raw = pipe.fileHandleForReading.readDataToEndOfFile()
                process.waitUntilExit()

                // Check the flag rather than terminationReason, which may not
                // reflect SIGTERM reliably if the process handles the signal
                if timedOut.wait(timeout: .now()) == .success {
                    continuation.resume(throwing: ConnectorError.keychainTimeout(serviceName: serviceName, timeoutSeconds: 10))
                    return
                }
                guard process.terminationStatus == 0 else {
                    continuation.resume(throwing: ConnectorError.keychainAccessDenied(serviceName: serviceName, exitCode: process.terminationStatus))
                    return
                }
                guard let jsonString = String(data: raw, encoding: .utf8)?.trimmingCharacters(in: .whitespacesAndNewlines),
                      !jsonString.isEmpty else {
                    continuation.resume(throwing: ConnectorError.keychainEmpty(serviceName: serviceName))
                    return
                }

                guard let jsonData = jsonString.data(using: .utf8) else {
                    continuation.resume(throwing: ConnectorError.tokenParseError(rawValue: jsonString))
                    return
                }
                let parsedJSON: [String: Any]
                do {
                    parsedJSON = try JSONSerialization.jsonObject(with: jsonData) as? [String: Any] ?? [:]
                } catch {
                    continuation.resume(throwing: ConnectorError.tokenParseError(rawValue: jsonString))
                    return
                }
                guard let oauthDict = parsedJSON["claudeAiOauth"] as? [String: Any],
                      let token = oauthDict["accessToken"] as? String,
                      !token.isEmpty else {
                    continuation.resume(throwing: ConnectorError.tokenParseError(rawValue: jsonString))
                    return
                }

                continuation.resume(returning: token)
            }
        }
    }

    // MARK: - Response parsing

    private static let sensitiveKeyPatterns = ["token", "key", "secret", "password", "email", "credential"]

    private static func maskedPayload(_ data: Data) -> String {
        guard let json = try? JSONSerialization.jsonObject(with: data) as? [String: Any] else {
            return "<non-JSON, \(data.count) bytes>"
        }
        let masked = maskSensitiveFields(json)
        guard let out = try? JSONSerialization.data(withJSONObject: masked, options: [.sortedKeys]),
              let str = String(data: out, encoding: .utf8) else {
            return "<serialization failed>"
        }
        return str
    }

    private static func maskSensitiveFields(_ dict: [String: Any]) -> [String: Any] {
        var result: [String: Any] = [:]
        for (key, value) in dict {
            let lower = key.lowercased()
            if sensitiveKeyPatterns.contains(where: { lower.contains($0) }) {
                result[key] = "***"
            } else if let nested = value as? [String: Any] {
                result[key] = maskSensitiveFields(nested)
            } else if let array = value as? [[String: Any]] {
                result[key] = array.map { maskSensitiveFields($0) }
            } else {
                result[key] = value
            }
        }
        return result
    }

    private struct ParsedUsage {
        let sessionPercent: Int
        let sessionResetAt: ISODate
        let weeklyPercent: Int
        let weeklyResetAt: ISODate
    }

    private func parseAPIResponse(_ data: Data) throws -> ParsedUsage {
        let jsonObject = try JSONSerialization.jsonObject(with: data)
        guard let json = jsonObject as? [String: Any] else {
            throw ConnectorError.unexpectedAPIFormat(receivedKeys: [])
        }
        guard let fiveHour = json["five_hour"] as? [String: Any],
              let sevenDay = json["seven_day"] as? [String: Any],
              let sessionUtil = fiveHour["utilization"] as? Double,
              let sessionReset = fiveHour["resets_at"] as? String,
              let weeklyUtil = sevenDay["utilization"] as? Double,
              let weeklyReset = sevenDay["resets_at"] as? String else {
            throw ConnectorError.unexpectedAPIFormat(receivedKeys: Array(json.keys))
        }
        return ParsedUsage(
            sessionPercent: Int(sessionUtil.rounded()),
            sessionResetAt: Self.normalizeISO8601(sessionReset),
            weeklyPercent: Int(weeklyUtil.rounded()),
            weeklyResetAt: Self.normalizeISO8601(weeklyReset)
        )
    }

    /// Strips sub-second precision from API-provided ISO8601 strings so downstream
    /// consumers can rely on the standard formatter (no fractional-seconds option needed).
    /// Returns the original string unchanged if it cannot be parsed.
    private static func normalizeISO8601(_ raw: String) -> ISODate {
        if let date = isoFormatterFractional.date(from: raw) ?? isoFormatter.date(from: raw) {
            return ISODate(rawValue: isoFormatter.string(from: date))
        }
        return ISODate(rawValue: raw)
    }

    // MARK: - Helpers

    private func errorEntry(account: AccountEmail, type: String, isActive: Bool = false, preservedMetrics: [UsageMetric] = []) -> VendorUsageEntry {
        return VendorUsageEntry(
            vendor: vendor,
            account: account,
            isActive: isActive,
            lastAcquiredOn: nil,
            lastError: UsageError(timestamp: ISODate(date: Date()), type: type),
            metrics: preservedMetrics
        )
    }
}

public enum ConnectorError: Error, CustomStringConvertible {
    case keychainAccessDenied(serviceName: String, exitCode: Int32)
    case keychainEmpty(serviceName: String)
    case keychainTimeout(serviceName: String, timeoutSeconds: Int)
    case tokenParseError(rawValue: String)
    case unexpectedAPIFormat(receivedKeys: [String])

    public var description: String {
        switch self {
        case let .keychainAccessDenied(svc, code):
            "Keychain access denied for service '\(svc)' (exit \(code))"
        case let .keychainEmpty(svc):
            "Keychain item is empty for service '\(svc)'"
        case let .keychainTimeout(svc, secs):
            "Keychain access timed out after \(secs)s for service '\(svc)'"
        case let .tokenParseError(raw):
            "Failed to parse OAuth token — raw value preview: '\(raw.prefix(80))'"
        case let .unexpectedAPIFormat(keys):
            "API response does not match expected format — top-level keys: \(keys)"
        }
    }
}

